const sessionCache = new TTLCache<SessionCacheEntry>({
  maxSize: 5000,
  defaultTtl: 30_000, // 30s — security-sensitive, short TTL
  onDispose: (key, value) => {
    // Clean up reverse index when entry expires or is evicted
    const sessionIds = userIndex.get(value.user.id);
    if (sessionIds) {
      sessionIds.delete(key);
      if (sessionIds.size === 0) userIndex.delete(value.user.id);
    }
  },
});

const bulkBodyLength = async (ctx: Context<Env>): Promise<number> => {
  try {
    const contentType = ctx.req.header('content-type');
    if (!contentType?.includes('application/json')) return 1;

    const body = await ctx.req.json();

    if (Array.isArray(body)) return Math.max(body.length, 1);
    if (body && Array.isArray(body.ids)) return Math.max(body.ids.length, 1);
  } catch {}

  return 1;
};

